import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { thanhToanAPI } from '../services/api';
import './ThanhToan.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function ThanhToan() {
  const [soDu, setSoDu] = useState(0);
  const [hoaDons, setHoaDons] = useState([]);
  const [napSoTien, setNapSoTien] = useState('');
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('vi');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [viRes, hdRes] = await Promise.all([
        thanhToanAPI.xemSoDu(),
        thanhToanAPI.layHoaDon(),
      ]);
      setSoDu(viRes.data.data || 0);
      setHoaDons(hdRes.data.data || []);
    } catch {}
    setLoading(false);
  };

  useEffect(() => { fetchData(); }, []);

  const handleNapTien = async () => {
    if (!napSoTien || isNaN(napSoTien)) { toast.error('Nhập số tiền hợp lệ'); return; }
    try {
      const res = await thanhToanAPI.napTien(parseFloat(napSoTien));
      setSoDu(res.data.data);
      setNapSoTien('');
      toast.success('Nạp tiền thành công!');
    } catch (e) { toast.error(e.response?.data?.message || 'Thất bại'); }
  };

  const handleThanhToan = async (maHoaDon) => {
    try {
      await thanhToanAPI.thanhToan(maHoaDon);
      toast.success('Thanh toán thành công!');
      fetchData();
    } catch (e) { toast.error(e.response?.data?.message || 'Thanh toán thất bại'); }
  };

  const presets = [500000, 1000000, 2000000, 5000000];

  if (loading) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <h1 className="section-title">💳 Thanh toán</h1>

      {/* Tabs */}
      <div className="tabs">
        {[['vi','💰 Ví tiền'], ['hoadon','📄 Hóa đơn']].map(([k, label]) => (
          <div key={k} className={`tab ${tab === k ? 'active' : ''}`} onClick={() => setTab(k)}>{label}</div>
        ))}
      </div>

      {tab === 'vi' && (
        <div className="grid-2" style={{ alignItems:'start' }}>
          {/* Wallet balance */}
          <div className="card">
            <div className="card-body">
              <div style={{ textAlign:'center', padding:'20px 0' }}>
                <div style={{ fontSize: 48 }}>💰</div>
                <div style={{ fontSize: 14, color:'var(--text-muted)', marginTop: 8 }}>Số dư hiện tại</div>
                <div className="balance-amount">{fmt(soDu)}</div>
              </div>
            </div>
          </div>

          {/* Nạp tiền */}
          <div className="card">
            <div className="card-header">Nạp tiền vào ví</div>
            <div className="card-body">
              <div className="preset-amounts">
                {presets.map(p => (
                  <button key={p} className={`preset-btn ${parseFloat(napSoTien) === p ? 'active' : ''}`}
                    onClick={() => setNapSoTien(String(p))}>
                    {fmt(p)}
                  </button>
                ))}
              </div>
              <div className="form-group" style={{ marginTop: 16 }}>
                <label className="form-label">Hoặc nhập số tiền</label>
                <input className="form-control" type="number" placeholder="Nhập số tiền..."
                  value={napSoTien} onChange={e => setNapSoTien(e.target.value)} />
              </div>
              <button className="btn btn-primary btn-block" onClick={handleNapTien}>
                ➕ Nạp tiền
              </button>
              <div className="alert alert-info" style={{ marginTop: 16, fontSize: 13 }}>
                ℹ️ Trong môi trường thực tế, nạp tiền sẽ tích hợp VNPay / MoMo / ZaloPay.
              </div>
            </div>
          </div>
        </div>
      )}

      {tab === 'hoadon' && (
        <div>
          {hoaDons.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">📄</div>
              <p>Chưa có hóa đơn nào.</p>
            </div>
          ) : (
            <div style={{ display:'flex', flexDirection:'column', gap: 14 }}>
              {hoaDons.map(hd => (
                <div key={hd.maHoaDon} className="card hoadon-item">
                  <div className="card-body">
                    <div className="hoadon-row">
                      <div>
                        <div className="hoadon-title">#{hd.maHoaDon} — {hd.tenPhong}</div>
                        <div style={{ color:'var(--text-muted)', fontSize: 13, marginTop: 4 }}>
                          {hd.moTa} · {hd.ngayTao ? new Date(hd.ngayTao).toLocaleDateString('vi-VN') : ''}
                        </div>
                      </div>
                      <div style={{ textAlign:'right' }}>
                        <div className="hoadon-amount">{fmt(hd.tongTien)}</div>
                        <span className={`badge ${hd.trangThai === 'Da thanh toan' ? 'badge-success' : 'badge-warning'}`}>
                          {hd.trangThai === 'Da thanh toan' ? '✅ Đã thanh toán' : '⏳ Chưa thanh toán'}
                        </span>
                        {hd.trangThai !== 'Da thanh toan' && (
                          <button className="btn btn-primary btn-sm" style={{ marginTop: 8, display:'block' }}
                            onClick={() => handleThanhToan(hd.maHoaDon)}>
                            Thanh toán ngay
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
